VALUES
  ('real-estate-moex-01044', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於子女之監護，下列敘述，何者錯誤？', '["夫妻離婚者，對於未成年子女權利義務之行使或負擔，原則上由夫任之", "夫妻未為協議或協議不成者，法院得依夫妻之一方、主管機關、社會福利機構或其他利害關係人之請 求或依職權酌定之", "協議不利於子女者，法院得依主管機關、社會福利機構或其他利害關係人之請求或依職權為子女之利 益改定之", "行使、負擔權利義務之一方未盡保護教養之義務或對未成年子女有不利之情事者，他方、未成年子女、 主管機關、社會福利機構或其他利害關係人得為子女之利益，請求法院改定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01045', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '年甫16歲之乙受第三人甲贈與房屋一間，乙之父母丙、丁均健在。下列敘述，何者正確？', '["丙、丁各得單獨管理該房屋", "非得乙之同意，丙、丁不得使用該房屋", "丙、丁得共同將該房屋出租收取租金", "丙為清償自身之債務，得將該房屋出售並移轉所有權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01046', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '某富婆在其遺囑中載明將遺產全部留給自己之愛狗繼承。依我國法律規定，狗可否取得該遺產？', '["可以", "不可以", "由繼承人決定", "由法院決定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01047', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲、乙夫婦因重大車禍入院，夫甲於入院當日死亡、妻乙於次日死亡。甲有弟一人丙、乙有母丁及妹一人 戊。甲之遺產總額為720萬元時，丙、丁、戊三人如何分配？', '["丙240萬元、丁240萬元、戊240萬元", "丙240萬元、丁300萬元、戊180萬元", "丙360萬元、丁360萬元、戊0元", "丙360萬元、丁180萬元、戊180萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01048', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲為18歲之人，未得法定代理人之允許，自書遺囑一份，寫明將所有財產全部捐給某公益團體。該遺囑 之效力如何？', '["效力未定，因為未得法定代理人之允許", "無效，因為未得法定代理人之允許", "有效，因為無須法定代理人之允許", "無效，因為內容違反特留分之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01049', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲死亡後，其法定繼承人為其妻乙及兄丙、妹丁，計算法定繼承人特留分之基礎財產額為 480 萬元。丁 之特留分金額為何？', '["60萬元", "40萬元", "30萬元", "20萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01050', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'essay', '甲被乙詐欺，將其所有之一棟房屋以低價賣給乙，並已為所有權移轉
登記。請問甲依民法第 92 條規定，僅撤銷債權行為，而未撤銷物權行
為時，當事人之間的法律關係如何？甲若同時撤銷債權行為與物權行
為時，其法律關係又是如何？另法律行為因被詐欺而為撤銷與因被脅
迫而為撤銷，其效力有何不同？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01051', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'essay', '甲、乙共有一筆土地，面積 100 平方公尺，僅符合建築面積最小單位，
應有部分分別為甲十分之八，乙十分之二，甲、乙以其應有部分分別向
丙、丁貸款，設定抵押權作為擔保。嗣甲請求分割，因與乙無法達成協
議，遂提起分割共有物之訴，法院依民法第 824 條第 3 項規定，判決將
該共有地分配於甲，並命甲補償乙新臺幣 100 萬元。請問乙對甲之補償
金債權，民法設有何種保障機制？又丁在乙之應有部分上原有之抵押權
如何處理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01052', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '依法律之規定，有使用文字之必要者，下列敘述何者正確？', '["須本人自寫，並親自簽名或蓋章", "得不由本人自寫，但必須親自簽名或蓋章", "如以指印、十字或其他符號代簽名者，在文件上，經一人簽名證明，亦與簽名生同等之效力", "如以指印、十字或其他符號代簽名者，在文件上，經一人以指印、十字或其他符號代簽名者證明，亦 與簽名生同等之效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01053', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於形成權，下列敘述何者正確？', '["所謂形成權係指當事人得依據雙方自由意志，形成法律關係之權利", "形成權的行使，原則上不得附條件或期限", "形成權的行使期間，法律多設有消滅時效", "同意權、抗辯權與解除權均屬形成權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
